+    return AutoTocOptions;
+  }
+
+  apply(text: string, options: AutoTocOptions): string {
+    const hasFinalNewline = text.endsWith('\
');
+    const lines = text.split('\
');
+    if (hasFinalNewline) lines.pop();
+
+    const startIndex = lines.findIndex((line) => tocStart.test(line));
+    if (startIndex === -1) return text;
+
+    const endIndex = lines.findIndex((line, index) => index > startIndex && tocEnd.test(line));
+    const regionEnd = endIndex === -1 ? startIndex : endIndex;
+    const headings = this.getHeadings(lines, startIndex, regionEnd, options);
+    const tocLines = this.buildToc(lines[startIndex], endIndex === -1 ? '<!-- /toc -->' : lines[endIndex], headings, options);
+
+    const result = [
+      ...lines.slice(0, startIndex),
+      ...tocLines,
+      ...lines.slice(endIndex === -1 ? startIndex + 1 : endIndex + 1),
+    ].join('\
');
+    return hasFinalNewline ? result + '\
' : result;
+  }
+
+  private getHeadings(lines: string[], tocStartIndex: number, tocEndIndex: number, options: AutoTocOptions): Heading[] {
+    const headings: Heading[] = [];
+    const anchorCounts = new Map<string, number>();
+    let inYaml = lines[0]?.trim() === '---';
+    let fence: string = null;
+    let inMath = false;
+
