+function resolveLinksAndRemoveImages(text: string): string {
+  return text
+      .replace(/!\\[\\[[^\\]]*\\]\\]/g, '')
+      .replace(/!\\[[^\\]]*\\]\\([^)]*\\)/g, '')
+      .replace(/\\[\\[([^\\]|]+)(?:\\|([^\\]]+))?\\]\\]/g, (_match, target, display) => display ?? target)
+      .replace(/\\[([^\\]]*)\\]\\([^)]*\\)/g, '$1');
+}
+
+function stripFormatting(text: string): string {
+  return text
+      .replace(/<[^>]*>/g, '')
+      .replace(/[`*_~]/g, '')
+      .replace(/\\\\([\\\\`*_{}\\[\\]<>()#+.!-])/g, '$1');
+}
+
+function makeAnchor(text: string): string {
+  return stripFormatting(text)
+      .toLowerCase()
+      .replace(/\\s+/g, '-')
+      .replace(/[^a-z0-9_-]/g, '')
+      .replace(/-+/g, '-')
+      .replace(/^-+|-+$/g, '');
+}
+
+function isExcluded(heading: string, exclusions: string[]): boolean {
+  return exclusions.some((exclusion) => {
+    if (exclusion.length > 2 && exclusion.startsWith('/') && exclusion.endsWith('/')) {
+      try {
+        return new RegExp(exclusion.slice(1, -1), 'i').test(heading);
+      } catch {
+        return false;
+      }
+    }
+    return exclusion.toLowerCase() === heading.toLowerCase();
+  });
